const entrada2 = $input.all()[1]?.json || {};

// Identificamos cuál es cuál basándonos en el Property ID que ya conocemos
// UronWeb: 516647540 | Docdoco: 516647539
let docdoco = {};
let uronweb = {};

if (entrada1.propertyId === "516647539") {
  docdoco = entrada1;
  uronweb = entrada2;
} else {
  docdoco = entrada2;
  uronweb = entrada1;
}

return {
  fecha: new Date().toLocaleDateString('es-AR'),
  vistasDocdoco: docdoco.screenPageViews || 0,
  vistasUronweb: uronweb.screenPageViews || 0
};

